/* 802ABFC0-802AC1BC       .text checkOnOuterSea__11JAIZelBasicFPf */
int JAIZelBasic::checkOnOuterSea(f32* r4) {
    if (r4 == NULL) {
        return -1;
    }
    *r4 = 0.0f;
    if (field_0x0224 != 0x12) {
        return -1;
    }
    if (mIslandRoomNo == dIsleRoom_SeaFloor_e) {
        return 4;
    }
    isle_area_s sp0C = mIsleArea[mIslandRoomNo];
    if (sp0C.field_0x0 > 50000.0f) {
        return 4;
    }
    int islandX = ((mIslandRoomNo - 1) % 7);
    f32 f5 = (islandX - 3) * 100000.0f;
    int islandY = ((mIslandRoomNo - 1) / 7);
    f32 f1 = (islandY - 3) * 100000.0f;
    f32 f2 = mAudioCamera->field_0x0->x - f5;
    f32 f1_2 = mAudioCamera->field_0x0->z - f1;
    f32 f6 = sp0C.field_0x0 - f2;
    f32 f0 = sp0C.field_0x8 - f1_2;
    *r4 = f6*f6 + f0*f0;
    *r4 = std::sqrtf(*r4);
    
    if (*r4 <= sp0C.field_0xC) {
        return 0;
    } else if (*r4 <= sp0C.field_0xC + 2000.0f) {
        return 1;
    } else if (*r4 <= sp0C.field_0xC + 3000.0f) {
        return 2;
    } else if (*r4 <= sp0C.field_0xC + 4000.0f) {
        return 3;
    } else {
        return 4;
    }
}

